class PhaseCheckpointAgent:
    CONFIDENCE_THRESHOLD = 0.85

    def __init__(self, goal):
        self.goal = goal
        self.plan = []
        self.log = []

    def make_plan(self):
        # Agent proposes a plan -- human approves before execution starts
        self.plan = self._generate_plan()
        print('Proposed plan for: ' + self.goal)
        for i, step in enumerate(self.plan):
            print('  ' + str(i+1) + '. ' + step['description'])
        answer = input('Approve this plan? [y/N] ').strip().lower()
        if answer != 'y':
            raise RuntimeError('Plan rejected by user')
        print('Plan approved. Executing autonomously...')

    def execute_plan(self):
        for step in self.plan:
            confidence = step.get('confidence', 1.0)
            if confidence < self.CONFIDENCE_THRESHOLD or step.get('irreversible'):
                # Exception: pause and ask even during autonomous execution
                print('[Agent] Low confidence or irreversible step: ' + step['description'])
                answer = input('Proceed? [y/N] ').strip().lower()
                if answer != 'y':
                    print('Stopping.')
                    return
            result = self._run_step(step)
            self.log.append({'step': step['description'], 'result': result})

    def _generate_plan(self):
        return [
            {'description': 'Read config file', 'confidence': 0.99},
            {'description': 'Fetch latest data', 'confidence': 0.95},
            {'description': 'Delete old records', 'confidence': 0.70, 'irreversible': True},
        ]

    def _run_step(self, step):
        return 'done'

agent = PhaseCheckpointAgent('refresh data store')
agent.make_plan()    # human approves plan
agent.execute_plan() # autonomous, but pauses on low-confidence/irreversible steps

class AutonomousAgentWithEscalation:
    def __init__(self, goal, approved_actions):
        self.goal = goal
        self.approved_actions = set(approved_actions)
        self.escalation_log = []

    def should_escalate(self, action, confidence, is_irreversible):
        reasons = []
        if action not in self.approved_actions:
            reasons.append('action ' + action + ' not in approved set')
        if confidence < 0.80:
            reasons.append('confidence ' + str(round(confidence, 2)) + ' below threshold')
        if is_irreversible:
            reasons.append('action is irreversible')
        return reasons

    def attempt_action(self, action, confidence, is_irreversible, fn, **params):
        reasons = self.should_escalate(action, confidence, is_irreversible)
        if reasons:
            print('[ESCALATE] ' + action + ': ' + ', '.join(reasons))
            self.escalation_log.append({'action': action, 'reasons': reasons})
            answer = input('Allow this action? [y/N] ').strip().lower()
            if answer != 'y':
                return None
        result = fn(**params)
        print('[DONE] ' + action + ' -> ' + str(result))
        return result

agent = AutonomousAgentWithEscalation(
    goal='archive old reports',
    approved_actions=['read_file', 'compress_file', 'move_to_archive'],
)
# This action was not pre-approved -- agent escalates
agent.attempt_action('delete_file', confidence=0.90, is_irreversible=True,
                     fn=lambda path: 'deleted', path='/reports/old.pdf')
